// src/backup/BackupDestinoDropbox.js
import React, { useState } from 'react';
import axios from 'axios';
import NProgress from 'nprogress';
import { toast } from 'react-toastify';
import { CloudUpload } from 'lucide-react';

NProgress.configure({ showSpinner: false, trickleSpeed: 120 });

const inputCls =
  'w-full border rounded px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-300';

export default function BackupDestinoDropbox() {
  const [folder, setFolder] = useState('/Backups');
  const [cleanupDays, setCleanupDays] = useState(30);
  const [loading, setLoading] = useState(false);
  const token = JSON.parse(localStorage.getItem('user') || '{}')?.token || localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}` };

  async function handleSend() {
    try {
      setLoading(true);
      NProgress.start();
      const body = {
        destinations: ['dropbox'],
        dropboxFolder: folder || '/Backups',
        cleanupDays: Number(cleanupDays) || 30,
      };
      const { data } = await axios.post('/api/backup/run', body, { headers });
      toast.success('Backup enviado para o Dropbox!');
      // debug opcional
      // console.log('DROPBOX RESULT:', data);
    } catch (err) {
      const reason = err?.response?.data?.reason || err?.message || 'Falha no backup para o Dropbox.';
      toast.error(reason);
    } finally {
      NProgress.done();
      setLoading(false);
    }
  }

  return (
    <div className="bg-white rounded-2xl shadow p-6">
      <h3 className="text-lg font-semibold text-gray-800 mb-2">Dropbox</h3>
      <p className="text-sm text-gray-600 mb-4">
        Envia o backup para a pasta informada e remove backups mais antigos que o período escolhido.
        Certifique-se de configurar o <b>DROPBOX_TOKEN</b> no backend.
      </p>

      <div className="mb-4 max-w-md">
        <label className="block text-sm font-medium text-gray-700">Pasta no Dropbox</label>
        <input
          type="text"
          className={inputCls}
          placeholder="/Backups"
          value={folder}
          onChange={(e) => setFolder(e.target.value)}
        />
      </div>

      <div className="mb-6 max-w-xs">
        <label className="block text-sm font-medium text-gray-700">Excluir backups com mais de (dias)</label>
        <input
          type="number"
          min={1}
          className={inputCls}
          value={cleanupDays}
          onChange={(e) => setCleanupDays(e.target.value)}
        />
      </div>

      <button
        onClick={handleSend}
        disabled={loading}
        className={`${
          loading ? 'opacity-70 cursor-not-allowed' : ''
        } bg-green-600 hover:bg-green-700 text-white font-bold px-4 py-2 rounded-full inline-flex items-center gap-2`}
      >
        {loading ? (
          <span className="inline-block h-4 w-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
        ) : (
          <CloudUpload size={18} />
        )}
        {loading ? 'Enviando...' : 'Enviar para Dropbox'}
      </button>
    </div>
  );
}
